import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class InputHandler {

    public void processInput(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        String sanitizedUserInput = sanitizeUserInput(userInput);

        String responseHtml = "<html><body>Welcome, " + sanitizedUserInput + "</body></html>";

        response.setContentType("text/html");
        response.getWriter().write(responseHtml);
    }

    private String sanitizeUserInput(String userInput) {
        // Implement proper input sanitization here, such as HTML encoding
